UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Course Requirement","This is a research-based PhD programme. The candidate is required to conduct independent research under an academic supervisor/supervisory committee, complete the thesis and orally defend his/her thesis in a proposal defence and attend a viva voce.","Other Requirement: Students are to acquire sufficient research skills training hours as prescribed by the faculty before the proposal defence. On top of this, a student undertaking research in the entrepreneurship-related area is required to undertake two Entrepreneurship modules:","Managing Innovation and Entrepreneurship.","The supervisor may prescribe other courses to the student to supplement their learning from time to time."]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'd7692546-ede1-4093-b75a-ef0f463c73eb';
