UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Semester one","In semester one, you will take modules in capital market analysis, corporate finance and quantitative research methods for finance.","Semester two","In semester two, you will take two further required modules on derivative investment and fixed interest investment. You will also complete two elective modules from any of the four topics from Behavioural Economics and Decision Making, International Finance, Managing Innovation and Entrepreneurship, and Consulting Skills.","Dissertation","After completing your semester two modules, you will undertake a 15,000-word dissertation, with one-to-one support from an expert academic supervisor. This will demonstrate your ability to undertake independent research in the area of finance and investment.","Modules","Semester one","Capital Market Analysis","Corporate Finance","Quantitative Research Methods for Finance and Investment","Semester two","Derivative Investment","Fixed Interest Investment","Any two of the following electives","Semester Three","Finance and Investment Dissertation"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '6fe91d51-4621-4a9c-a9b3-ba29305a665a';
