UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Participating Faculties","Faculty of Electrical Technology and Engineering","Faculty of Electronic and Computer Technology and Engineering","Faculty of Mechanical Technology and Engineering","Faculty of Industrial and Manufacturing Technology and Engineering","Programme Structure","DEng programme consists of two components, i.e. taught course and research.","Components","Particular","Taught Course","- Modules are designed to enhance candidates’ knowledge","Research","- Based on real industrial problems","Taught Course:","Research:","The candidate will normally be advised by one academic supervisor and one industrial supervisor. The topic for the research will be jointly decided by the faculty and the participating company. It can be a single project, or a series of projects, firmly based on a real industrial problem and having significant challenging and innovative engineering content. The candidate will spend majority of his/her time (about 80%) with the collaborating company."]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'e4e23b1a-afbd-4977-b304-9ab26e68d702';
