UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Programme Module","The Master of Applied Sciences programme encompasses the following five phases:","Phase II - Preliminary ResearchThis represents the first part of the Master''s thesis project and forms the basis on which students build their proposal and eventually their project.","Phase III - Proposal DefenceEach student must publicly present and defend his/her research proposals.","The student is only allowed to continue with his/her research to Phase IV on passing of the defence of his/her proposal.","Phase IV - Thesis PreparationThe student proceeds to his/her data collection, data analysis and report writing.","Phase V - Viva VoceAfter completion and submission of the thesis, the student is required to attend a Viva Voce to orally defend his/her thesis."]}]'::jsonb, entry_requirements_text = NULL WHERE id = '74dd5267-ca30-432d-a780-d579a25df262';
