UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Current areas of research","We encourage applications in any topic related to English. Our current research topics include:","19th-Century British and American Literature","Creative Writing","Discourse Analysis","Fairy Tale","Gender Studies","Gothic","Grammar","Identity","Language in the Classroom","Malaysia Literature","New literatures in English","Stylistics","World Englishes","Research training","The School also offers research training seminars and students also have access to training programmes offered by the graduate school. The University also has an early-career researchers’ network which provides peer-support for students.","Exceptional candidates working in areas of research deemed priority areas for the school may also be eligible to partial fee waiver scholarships at the discretion of the Programme Director."]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'ffc8cf33-f427-44b2-96bb-c496994d124a';
