UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Our research covers areas including:","comparative literature, Japanese literature, literary translation","digital cultures, youth and social networks","food, identity and transnationalism","international information flows – questions of imbalance, cultural and media imperialism and dependency","media and human rights – these include communication rights, media and gender relations, and media and minority groups","performing arts: music, drama, performance, applied creative practices","Southeast Asian cinema, particularly Indonesian, Malaysian and Singaporean films","the history, policies and structures of the culture industries - these encompass structural analysis, political economy and post-colonial development studies"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'ef148525-ae97-40da-8b91-169a06e6815a';
