UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Course content","Research collaboration is promoted through The University of Nottingham’s Research Priority Groups. Principally with two groups, Integrating Global Society and Science, Technology and Society. Cooperation is also sought through staff and student membership of our sub-discipline, tri-campus research centres:","Centre for Conflict, Security and Terrorism","Centre for the Study of Social and Global Justice","Centre for the Study of European Governance","University of Nottingham Asia Research Institute"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '659487a4-5cf1-4883-bf3c-901d919f7604';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Typical core modules","Debating Special and Inclusive Education","This module focuses on critical issues in special education and inclusive education across the globe, and application of theories, policies, societal issues, and education and inclusive systems on educational provision for individuals who are marginalised, including those with special needs.","Key topics include:","Critiquing definitions of special and inclusive education.","Exploring the sociological, political and theoretical perspectives of inclusion.","Understanding inclusive pedagogies and systems.","Practice Based InquiryThe content will involve you in active critical consideration of participating in and leadership of practitioner inquiry in relation to professional context mapping and workplace learning.","These processes will be achieved through:","conceptualising different kinds of practitioner inquiry relevant to work-based understanding and development (purposes, processes, contexts, dilemmas, outcomes).","examining a range of approaches to educational inquiry, with an emphasis on action research.","developing an inquiry into your professional context.","Dissertation","This substantive piece of scholarship within the field of the course will normally be based on interests and skills you have developed in the course of the modules already studied.","You will choose a topic in consultation with your course leader and an appropriate supervisor.","Typical optional modules","Communication and Literacy","This module focuses on the importance of communication and its close links to the development of literacy. This module explores the development of both communication and literacy skills, issues that arise in individuals with communication and literacy difficulties and educational support for communication and literacy development.","Key topics include:","Critiquing theories of communication and literacy development.","Understanding the impact of communication and literacy difficulties including among individuals with learning disability, autism, Down syndrome and dyslexia.","Evaluating communication and literacy assessments and interventions.","Responding Mindfully to Challenging Behavior","This module focuses on developing a critical understanding of theories on behaviour and relationship management, and reflecting on how these theories influence practical issues concerning the management of individuals with special needs.","Key topics include:","Developing an awareness in reflexivity as a key resource and skill in facilitating other individuals and groups.","Relating theories and practices related to managing relationships and behaviour in educational contexts.","Understanding of whole school issues relating to responding mindfully to challenging behaviours and meeting the needs of individuals with social, emotional and behavioural difficulties.","Meet the tutor","Please note that we offer only one or two modules at each teaching time point.","To maximise your study period, we highly encourage that you align your programme start date with the first module of your choice.","Please email the programme coordinator if you need help with module selection."]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'c2bc7bff-22d3-4ab1-89c7-79ab92f6776b';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["To be awarded a MA TESOL, you need to complete and pass four modules (two core and two elective) plus a dissertation.","Typical core modules","Language Teaching: Methodology and"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'e333afd6-d633-485f-9415-8d8f45d56eb2';
